FILES = {'src/claire/verified_memory/__init__.py': '"""\nClaire v17.61 Verified Memory + Recursive Feedback Gate.\n\nThis package does not perform autonomous learning. It creates the governance gate\nthat decides whether a validated Claire output may enter verified memory and\nwhether recursive feedback is permitted.\n"""\n\nfrom .memory_gate import MemoryGate, build_memory_gate_report\nfrom .recursive_feedback_gate import RecursiveFeedbackGate, build_recursive_feedback_report\n\n__all__ = [\n    "MemoryGate",\n    "RecursiveFeedbackGate",\n    "build_memory_gate_report",\n    "build_recursive_feedback_report",\n]\n', 'src/claire/verified_memory/io.py': 'from __future__ import annotations\n\nimport json\nfrom pathlib import Path\nfrom typing import Any, Dict, Optional\n\n\ndef load_json(path: Path) -> Dict[str, Any]:\n    with path.open("r", encoding="utf-8") as handle:\n        data = json.load(handle)\n    if not isinstance(data, dict):\n        raise ValueError(f"Expected JSON object in {path}")\n    return data\n\n\ndef write_json(path: Path, data: Dict[str, Any]) -> None:\n    path.parent.mkdir(parents=True, exist_ok=True)\n    with path.open("w", encoding="utf-8") as handle:\n        json.dump(data, handle, indent=2, ensure_ascii=False)\n        handle.write("\\n")\n\n\ndef find_latest_file(project_root: Path, file_name: str) -> Optional[Path]:\n    candidates = [\n        project_root / "exports" / "latest" / file_name,\n        project_root / "output" / file_name,\n        project_root / file_name,\n    ]\n\n    for candidate in candidates:\n        if candidate.exists():\n            return candidate\n\n    export_root = project_root / "exports"\n    if export_root.exists():\n        possible = [path for path in export_root.glob(f"**/{file_name}") if path.is_file()]\n        if possible:\n            possible.sort(key=lambda path: path.stat().st_mtime, reverse=True)\n            return possible[0]\n\n    return None\n\n\ndef find_runtime_truth(project_root: Path) -> Optional[Path]:\n    return find_latest_file(project_root, "dashboard_runtime_truth.json") or find_latest_file(project_root, "core_run_output.json")\n\n\ndef find_validation_report(project_root: Path) -> Optional[Path]:\n    return find_latest_file(project_root, "validation_authority_report.json")\n', 'src/claire/verified_memory/memory_record.py': 'from __future__ import annotations\n\nfrom dataclasses import dataclass, asdict\nfrom datetime import datetime, timezone\nfrom typing import Any, Dict, List\n\n\ndef utc_now() -> str:\n    return datetime.now(timezone.utc).isoformat().replace("+00:00", "Z")\n\n\n@dataclass\nclass MemoryRecord:\n    memory_id: str\n    run_id: str\n    route_selected: str\n    terminal_state: str\n    validation_score: int\n    source_output_path: str\n    evidence_count: int\n    created_at: str\n    tags: List[str]\n\n    def to_dict(self) -> Dict[str, Any]:\n        return asdict(self)\n\n\ndef build_memory_id(run_id: str, route_selected: str, terminal_state: str) -> str:\n    cleaned = f"{run_id}-{route_selected}-{terminal_state}".lower()\n    cleaned = "".join(ch if ch.isalnum() else "-" for ch in cleaned).strip("-")\n    while "--" in cleaned:\n        cleaned = cleaned.replace("--", "-")\n    return f"mem-{cleaned[:96] or \'unknown\'}"\n', 'src/claire/verified_memory/memory_gate.py': 'from __future__ import annotations\n\nfrom datetime import datetime, timezone\nfrom pathlib import Path\nfrom typing import Any, Dict, List, Optional\n\nfrom .memory_record import MemoryRecord, build_memory_id, utc_now\n\n\nPASS_STATUSES = {"pass", "passed", "valid", "verified", "true"}\nVALID_TERMINALS_FOR_MEMORY = {\n    "trend_thesis_ready",\n    "portfolio_action_ready",\n    "portfolio_optimization_ready",\n    "discovery_ready",\n    "breakthrough_classified",\n    "advancement_path_selected",\n    "design_output_ready",\n    "acquisition_package_ready",\n    "acquisition_ready",\n    "final_package_ready",\n}\n\n\ndef _first_present(mapping: Dict[str, Any], keys: List[str], default: Any = None) -> Any:\n    for key in keys:\n        value = mapping.get(key)\n        if value not in (None, ""):\n            return value\n    return default\n\n\ndef _section(mapping: Dict[str, Any], key: str) -> Dict[str, Any]:\n    value = mapping.get(key)\n    return value if isinstance(value, dict) else {}\n\n\ndef _boolish(value: Any) -> bool:\n    if isinstance(value, bool):\n        return value\n    if value is None:\n        return False\n    return str(value).strip().lower() in PASS_STATUSES\n\n\ndef _validation_passed(validation_report: Dict[str, Any], runtime_truth: Dict[str, Any]) -> bool:\n    if validation_report:\n        status = validation_report.get("validation_authority_status")\n        explicit = validation_report.get("validation_passed")\n        return str(status).lower() == "pass" and _boolish(explicit)\n\n    validation_truth = _section(runtime_truth, "validation_truth")\n    return _boolish(_first_present(validation_truth, ["validation_passed", "passed", "is_valid"], False))\n\n\ndef _run_id(validation_report: Dict[str, Any], runtime_truth: Dict[str, Any]) -> str:\n    run_truth = _section(runtime_truth, "run_truth")\n    return str(\n        validation_report.get("run_id")\n        or _first_present(run_truth, ["run_id", "id"], None)\n        or runtime_truth.get("run_id")\n        or "unknown"\n    )\n\n\ndef _route(validation_report: Dict[str, Any], runtime_truth: Dict[str, Any]) -> str:\n    route_truth = _section(runtime_truth, "route_truth")\n    run_truth = _section(runtime_truth, "run_truth")\n    return str(\n        validation_report.get("route_selected")\n        or _first_present(route_truth, ["route_selected", "selected_route", "route"], None)\n        or _first_present(run_truth, ["selected_route", "route_selected", "route"], None)\n        or runtime_truth.get("route_selected")\n        or "unknown"\n    )\n\n\ndef _terminal(validation_report: Dict[str, Any], runtime_truth: Dict[str, Any]) -> str:\n    terminal_truth = _section(runtime_truth, "terminal_truth")\n    run_truth = _section(runtime_truth, "run_truth")\n    return str(\n        validation_report.get("terminal_state")\n        or _first_present(terminal_truth, ["terminal_state", "state"], None)\n        or _first_present(run_truth, ["terminal_state"], None)\n        or runtime_truth.get("terminal_state")\n        or "missing"\n    )\n\n\ndef _evidence_count(validation_report: Dict[str, Any], runtime_truth: Dict[str, Any]) -> int:\n    summary = validation_report.get("evidence_summary") if isinstance(validation_report.get("evidence_summary"), dict) else {}\n    if summary.get("evidence_count") is not None:\n        try:\n            return int(summary.get("evidence_count"))\n        except Exception:\n            return 0\n\n    evidence_truth = _section(runtime_truth, "evidence_truth")\n    for key in ("evidence_count", "count"):\n        if evidence_truth.get(key) is not None:\n            try:\n                return int(evidence_truth.get(key))\n            except Exception:\n                pass\n    evidence = evidence_truth.get("evidence") or evidence_truth.get("evidence_chain") or runtime_truth.get("evidence_chain") or []\n    return len(evidence) if isinstance(evidence, list) else 0\n\n\nclass MemoryGate:\n    """Decide whether a Claire output may enter verified memory."""\n\n    contract_version = "claire.verified_memory_gate.v17.61"\n\n    def evaluate(\n        self,\n        runtime_truth: Dict[str, Any],\n        validation_report: Optional[Dict[str, Any]] = None,\n        source_output_path: str = "",\n    ) -> Dict[str, Any]:\n        validation_report = validation_report or {}\n        run_id = _run_id(validation_report, runtime_truth)\n        route_selected = _route(validation_report, runtime_truth)\n        terminal_state = _terminal(validation_report, runtime_truth)\n        evidence_count = _evidence_count(validation_report, runtime_truth)\n\n        validation_passed = _validation_passed(validation_report, runtime_truth)\n        validation_status = validation_report.get("validation_authority_status") or _section(runtime_truth, "validation_truth").get("validation_status") or "unknown"\n        validation_score = int(validation_report.get("validation_score") or 0)\n\n        reasons: List[str] = []\n        blockers: List[str] = []\n\n        if not validation_passed:\n            blockers.append("validation_authority_not_passed")\n            reasons.append("Validation authority has not passed; output cannot enter verified memory.")\n\n        if terminal_state not in VALID_TERMINALS_FOR_MEMORY:\n            blockers.append("terminal_state_not_memory_eligible")\n            reasons.append(f"Terminal state \'{terminal_state}\' is not eligible for verified memory.")\n\n        if evidence_count <= 0:\n            blockers.append("no_evidence_traceability")\n            reasons.append("No evidence traceability was found; memory storage is blocked.")\n\n        if run_id == "unknown":\n            blockers.append("missing_run_id")\n            reasons.append("Run ID is missing; memory record cannot be tied to a source run.")\n\n        memory_eligible = len(blockers) == 0\n        memory_status = "eligible" if memory_eligible else "blocked"\n\n        memory_record = None\n        if memory_eligible:\n            memory_record = MemoryRecord(\n                memory_id=build_memory_id(run_id, route_selected, terminal_state),\n                run_id=run_id,\n                route_selected=route_selected,\n                terminal_state=terminal_state,\n                validation_score=validation_score,\n                source_output_path=source_output_path,\n                evidence_count=evidence_count,\n                created_at=utc_now(),\n                tags=[\n                    "verified_output",\n                    f"route:{route_selected}",\n                    f"terminal:{terminal_state}",\n                ],\n            ).to_dict()\n\n        return {\n            "schema": "claire.verified_memory_gate_report.v1",\n            "contract_version": self.contract_version,\n            "generated_at": utc_now(),\n            "run_id": run_id,\n            "route_selected": route_selected,\n            "terminal_state": terminal_state,\n            "validation_status": validation_status,\n            "validation_passed": validation_passed,\n            "validation_score": validation_score,\n            "evidence_count": evidence_count,\n            "memory_status": memory_status,\n            "memory_eligible": memory_eligible,\n            "memory_blockers": blockers,\n            "memory_reasons": reasons or ["Validation passed, evidence exists, terminal state is eligible, and run ID is present."],\n            "memory_record": memory_record,\n            "storage_mode": "gated_report_only",\n            "storage_note": "v17.61 does not autonomously write long-term memory. It produces a verified memory eligibility report and record payload for a future storage layer.",\n        }\n\n\ndef build_memory_gate_report(\n    runtime_truth: Dict[str, Any],\n    validation_report: Optional[Dict[str, Any]] = None,\n    source_output_path: str = "",\n) -> Dict[str, Any]:\n    return MemoryGate().evaluate(runtime_truth, validation_report, source_output_path)\n', 'src/claire/verified_memory/recursive_feedback_gate.py': 'from __future__ import annotations\n\nfrom typing import Any, Dict, List, Optional\n\nfrom .memory_record import utc_now\n\n\nFEEDBACK_ELIGIBLE_ROUTES = {\n    "portfolio",\n    "portfolio_optimization",\n    "breakthrough",\n    "autodesign",\n    "design",\n    "system_design",\n    "acquisition",\n    "package",\n}\n\n\nclass RecursiveFeedbackGate:\n    """Decide whether a verified output may be fed back into future Claire runs."""\n\n    contract_version = "claire.recursive_feedback_gate.v17.61"\n\n    def evaluate(self, memory_gate_report: Dict[str, Any]) -> Dict[str, Any]:\n        route = str(memory_gate_report.get("route_selected") or "unknown").lower()\n        memory_eligible = bool(memory_gate_report.get("memory_eligible"))\n        validation_passed = bool(memory_gate_report.get("validation_passed"))\n        memory_record = memory_gate_report.get("memory_record") if isinstance(memory_gate_report.get("memory_record"), dict) else None\n\n        blockers: List[str] = []\n        reasons: List[str] = []\n\n        if not validation_passed:\n            blockers.append("validation_not_passed")\n            reasons.append("Recursive feedback is blocked because validation did not pass.")\n\n        if not memory_eligible:\n            blockers.append("memory_not_eligible")\n            reasons.append("Recursive feedback is blocked because verified memory eligibility failed.")\n\n        if not memory_record:\n            blockers.append("missing_memory_record")\n            reasons.append("Recursive feedback is blocked because no verified memory record payload exists.")\n\n        if route not in FEEDBACK_ELIGIBLE_ROUTES:\n            blockers.append("route_not_feedback_eligible")\n            reasons.append(f"Route \'{route}\' is not currently approved for recursive feedback.")\n\n        allowed = len(blockers) == 0\n\n        return {\n            "schema": "claire.recursive_feedback_gate_report.v1",\n            "contract_version": self.contract_version,\n            "generated_at": utc_now(),\n            "run_id": memory_gate_report.get("run_id", "unknown"),\n            "route_selected": memory_gate_report.get("route_selected", "unknown"),\n            "terminal_state": memory_gate_report.get("terminal_state", "missing"),\n            "recursive_feedback_allowed": allowed,\n            "feedback_status": "allowed" if allowed else "blocked",\n            "feedback_blockers": blockers,\n            "feedback_reasons": reasons or ["Validated output is memory-eligible and may be used as governed recursive feedback."],\n            "feedback_payload": {\n                "memory_id": memory_record.get("memory_id") if memory_record else None,\n                "run_id": memory_gate_report.get("run_id", "unknown"),\n                "route_selected": memory_gate_report.get("route_selected", "unknown"),\n                "terminal_state": memory_gate_report.get("terminal_state", "missing"),\n                "allowed_uses": [\n                    "future_context_reference",\n                    "architecture_gap_analysis",\n                    "validated_output_replay",\n                    "route_quality_learning",\n                ] if allowed else [],\n            },\n            "safety_note": "v17.61 permits recursive feedback only as a governed status/payload. It does not autonomously mutate the runtime or retrain models.",\n        }\n\n\ndef build_recursive_feedback_report(memory_gate_report: Dict[str, Any]) -> Dict[str, Any]:\n    return RecursiveFeedbackGate().evaluate(memory_gate_report)\n', 'tools/claire_build_verified_memory.py': 'from __future__ import annotations\n\nimport argparse\nimport sys\nfrom pathlib import Path\n\n\ndef _bootstrap_project_imports(project_root: Path) -> None:\n    for candidate in (project_root, project_root / "src"):\n        candidate_str = str(candidate)\n        if candidate.exists() and candidate_str not in sys.path:\n            sys.path.insert(0, candidate_str)\n\n\ndef main() -> int:\n    parser = argparse.ArgumentParser(\n        description="Build Claire v17.61 verified memory and recursive feedback gate reports."\n    )\n    parser.add_argument("--project-root", default=".", help="Claire project root. Defaults to current directory.")\n    parser.add_argument("--runtime-truth", default=None, help="Optional runtime truth JSON path.")\n    parser.add_argument("--validation-report", default=None, help="Optional validation authority report path.")\n    parser.add_argument("--out-dir", default=None, help="Output directory. Defaults to exports/latest.")\n    args = parser.parse_args()\n\n    project_root = Path(args.project_root).resolve()\n    _bootstrap_project_imports(project_root)\n\n    try:\n        from claire.verified_memory.io import (\n            find_runtime_truth,\n            find_validation_report,\n            load_json,\n            write_json,\n        )\n        from claire.verified_memory.memory_gate import build_memory_gate_report\n        from claire.verified_memory.recursive_feedback_gate import build_recursive_feedback_report\n    except Exception as exc:\n        print(f"[Claire v17.61] Import error: {exc}", file=sys.stderr)\n        print("[Claire v17.61] Make sure you run this from the project root after installing v17.61.", file=sys.stderr)\n        return 2\n\n    runtime_path = Path(args.runtime_truth).resolve() if args.runtime_truth else find_runtime_truth(project_root)\n    validation_path = Path(args.validation_report).resolve() if args.validation_report else find_validation_report(project_root)\n\n    if runtime_path is None or not runtime_path.exists():\n        print("[Claire v17.61] No runtime truth found.", file=sys.stderr)\n        print("[Claire v17.61] Run Claire, then run tools/claire_build_runtime_truth.py.", file=sys.stderr)\n        return 1\n\n    if validation_path is None or not validation_path.exists():\n        print("[Claire v17.61] No validation authority report found.", file=sys.stderr)\n        print("[Claire v17.61] Run tools/claire_validate_runtime_truth.py before this command.", file=sys.stderr)\n        return 1\n\n    out_dir = Path(args.out_dir).resolve() if args.out_dir else project_root / "exports" / "latest"\n    frontend_dir = project_root / "src" / "frontend" / "command_center" / "modern"\n\n    runtime_truth = load_json(runtime_path)\n    validation_report = load_json(validation_path)\n\n    memory_report = build_memory_gate_report(\n        runtime_truth=runtime_truth,\n        validation_report=validation_report,\n        source_output_path=str(runtime_path),\n    )\n    recursive_report = build_recursive_feedback_report(memory_report)\n\n    memory_report["runtime_truth_input_path"] = str(runtime_path)\n    memory_report["validation_report_input_path"] = str(validation_path)\n    recursive_report["memory_gate_input_path"] = str(out_dir / "verified_memory_gate_report.json")\n\n    write_json(out_dir / "verified_memory_gate_report.json", memory_report)\n    write_json(out_dir / "recursive_feedback_gate_report.json", recursive_report)\n\n    if frontend_dir.exists():\n        write_json(frontend_dir / "verified_memory_status.json", memory_report)\n        write_json(frontend_dir / "recursive_feedback_status.json", recursive_report)\n\n    print("[Claire v17.61] Verified memory gate report written:")\n    print(f"  {out_dir / \'verified_memory_gate_report.json\'}")\n    print("[Claire v17.61] Recursive feedback gate report written:")\n    print(f"  {out_dir / \'recursive_feedback_gate_report.json\'}")\n    print(f"[Claire v17.61] Memory: {memory_report.get(\'memory_status\')} | Recursion: {recursive_report.get(\'feedback_status\')}")\n    return 0\n\n\nif __name__ == "__main__":\n    raise SystemExit(main())\n', 'src/frontend/command_center/modern/verified_memory_contract.json': '{\n  "schema": "claire.verified_memory_contract.v1",\n  "version": "17.61",\n  "purpose": "Dashboard-facing contract for verified memory eligibility.",\n  "canonical_outputs": [\n    "exports/latest/verified_memory_gate_report.json",\n    "src/frontend/command_center/modern/verified_memory_status.json"\n  ],\n  "required_fields": [\n    "schema",\n    "contract_version",\n    "generated_at",\n    "run_id",\n    "route_selected",\n    "terminal_state",\n    "validation_status",\n    "validation_passed",\n    "validation_score",\n    "evidence_count",\n    "memory_status",\n    "memory_eligible",\n    "memory_blockers",\n    "memory_reasons",\n    "memory_record",\n    "storage_mode"\n  ],\n  "rule": "Memory is eligible only when validation passes, evidence exists, terminal state is memory-eligible, and run_id exists.",\n  "no_fake_storage_rule": "v17.61 produces an eligibility report and record payload only; it does not pretend long-term memory storage occurred."\n}\n', 'src/frontend/command_center/modern/recursive_feedback_contract.json': '{\n  "schema": "claire.recursive_feedback_contract.v1",\n  "version": "17.61",\n  "purpose": "Dashboard-facing contract for governed recursive feedback eligibility.",\n  "canonical_outputs": [\n    "exports/latest/recursive_feedback_gate_report.json",\n    "src/frontend/command_center/modern/recursive_feedback_status.json"\n  ],\n  "required_fields": [\n    "schema",\n    "contract_version",\n    "generated_at",\n    "run_id",\n    "route_selected",\n    "terminal_state",\n    "recursive_feedback_allowed",\n    "feedback_status",\n    "feedback_blockers",\n    "feedback_reasons",\n    "feedback_payload",\n    "safety_note"\n  ],\n  "rule": "Recursive feedback is allowed only when validation passed, verified memory is eligible, a memory record payload exists, and the route is approved."\n}\n', 'src/frontend/command_center/modern/verified_memory_status.json': '{\n  "schema": "claire.verified_memory_gate_report.v1",\n  "version": "17.61",\n  "memory_status": "not_generated",\n  "memory_eligible": false,\n  "memory_blockers": [\n    "not_generated"\n  ],\n  "memory_reasons": [\n    "Run tools/claire_build_verified_memory.py after runtime truth and validation reports exist."\n  ],\n  "memory_record": null\n}\n', 'src/frontend/command_center/modern/recursive_feedback_status.json': '{\n  "schema": "claire.recursive_feedback_gate_report.v1",\n  "version": "17.61",\n  "feedback_status": "not_generated",\n  "recursive_feedback_allowed": false,\n  "feedback_blockers": [\n    "not_generated"\n  ],\n  "feedback_reasons": [\n    "Run tools/claire_build_verified_memory.py after validation authority passes."\n  ],\n  "feedback_payload": {}\n}\n', 'src/frontend/command_center/modern/claire_verified_memory.js': '(function () {\n  "use strict";\n\n  const MEMORY_PATHS = [\n    "verified_memory_status.json",\n    "./verified_memory_status.json",\n    "/src/frontend/command_center/modern/verified_memory_status.json",\n    "/exports/latest/verified_memory_gate_report.json",\n    "../../../exports/latest/verified_memory_gate_report.json",\n    "exports/latest/verified_memory_gate_report.json"\n  ];\n\n  const FEEDBACK_PATHS = [\n    "recursive_feedback_status.json",\n    "./recursive_feedback_status.json",\n    "/src/frontend/command_center/modern/recursive_feedback_status.json",\n    "/exports/latest/recursive_feedback_gate_report.json",\n    "../../../exports/latest/recursive_feedback_gate_report.json",\n    "exports/latest/recursive_feedback_gate_report.json"\n  ];\n\n  function escapeHtml(value) {\n    return String(value ?? "")\n      .replace(/&/g, "&amp;")\n      .replace(/</g, "&lt;")\n      .replace(/>/g, "&gt;")\n      .replace(/"/g, "&quot;");\n  }\n\n  async function fetchFirstJson(paths) {\n    for (const path of paths) {\n      try {\n        const response = await fetch(path, { cache: "no-store" });\n        if (response.ok) return await response.json();\n      } catch (_) {}\n    }\n    return null;\n  }\n\n  function ensureStyles() {\n    if (document.getElementById("claire-verified-memory-style")) return;\n    const style = document.createElement("style");\n    style.id = "claire-verified-memory-style";\n    style.textContent = `\n      .claire-memory-panel {\n        margin: 18px 0;\n        padding: 18px;\n        border: 1px solid rgba(168, 85, 247, 0.28);\n        border-radius: 18px;\n        background: linear-gradient(135deg, rgba(10, 8, 24, 0.96), rgba(19, 15, 36, 0.94));\n        color: #e2e8f0;\n        box-shadow: 0 0 28px rgba(168, 85, 247, 0.08);\n      }\n      .claire-memory-panel * { box-sizing: border-box; white-space: normal; overflow-wrap: anywhere; }\n      .claire-memory-header { display: flex; justify-content: space-between; align-items: flex-start; gap: 14px; margin-bottom: 14px; }\n      .claire-memory-title {\n        font-family: Orbitron, Inter, system-ui, sans-serif;\n        color: #c084fc;\n        font-size: 13px;\n        letter-spacing: .16em;\n        text-transform: uppercase;\n        font-weight: 800;\n      }\n      .claire-memory-subtitle { color: #94a3b8; font-size: 12px; line-height: 1.5; margin-top: 4px; }\n      .claire-memory-pill {\n        display: inline-flex;\n        align-items: center;\n        justify-content: center;\n        min-width: 92px;\n        padding: 7px 10px;\n        border-radius: 999px;\n        font-size: 11px;\n        font-weight: 800;\n        letter-spacing: .08em;\n        text-transform: uppercase;\n      }\n      .claire-memory-eligible, .claire-memory-allowed { color: #22c55e; border: 1px solid rgba(34,197,94,.45); background: rgba(34,197,94,.08); }\n      .claire-memory-blocked, .claire-memory-not_generated { color: #f59e0b; border: 1px solid rgba(245,158,11,.45); background: rgba(245,158,11,.08); }\n      .claire-memory-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(155px, 1fr)); gap: 10px; margin: 14px 0; }\n      .claire-memory-metric { border: 1px solid rgba(148, 163, 184, .16); border-radius: 14px; padding: 12px; background: rgba(15, 23, 42, .48); }\n      .claire-memory-label { color: #94a3b8; font-size: 10px; letter-spacing: .1em; text-transform: uppercase; margin-bottom: 5px; }\n      .claire-memory-value { color: #f8fafc; font-weight: 800; font-size: 14px; line-height: 1.35; }\n      .claire-memory-reasons { display: grid; gap: 8px; margin-top: 12px; }\n      .claire-memory-reason { border: 1px solid rgba(148, 163, 184, .14); border-radius: 12px; padding: 10px; background: rgba(2, 6, 23, .32); color: #cbd5e1; font-size: 12px; line-height: 1.5; }\n    `;\n    document.head.appendChild(style);\n  }\n\n  function findMount() {\n    const ids = [\n      "memory",\n      "memory-surface",\n      "surface-memory",\n      "claire-memory-surface",\n      "main-workspace",\n      "workspace",\n      "app"\n    ];\n    for (const id of ids) {\n      const node = document.getElementById(id);\n      if (node) return node;\n    }\n    return document.querySelector("main") || document.body;\n  }\n\n  function classFor(status) {\n    const normalized = String(status || "not_generated").toLowerCase().replace(/\\s+/g, "_");\n    return `claire-memory-${normalized}`;\n  }\n\n  function metric(label, value) {\n    return `\n      <div class="claire-memory-metric">\n        <div class="claire-memory-label">${escapeHtml(label)}</div>\n        <div class="claire-memory-value">${escapeHtml(value)}</div>\n      </div>\n    `;\n  }\n\n  function render(memory, feedback) {\n    ensureStyles();\n\n    let panel = document.getElementById("claire-verified-memory-panel");\n    if (!panel) {\n      panel = document.createElement("section");\n      panel.id = "claire-verified-memory-panel";\n      panel.className = "claire-memory-panel";\n      findMount().appendChild(panel);\n    }\n\n    const memoryStatus = memory?.memory_status || "not_generated";\n    const feedbackStatus = feedback?.feedback_status || "not_generated";\n    const reasons = [\n      ...(Array.isArray(memory?.memory_reasons) ? memory.memory_reasons : []),\n      ...(Array.isArray(feedback?.feedback_reasons) ? feedback.feedback_reasons : [])\n    ];\n    const reasonHtml = reasons.length\n      ? reasons.slice(0, 8).map((reason) => `<div class="claire-memory-reason">${escapeHtml(reason)}</div>`).join("")\n      : `<div class="claire-memory-reason">No verified memory report has been generated yet. Run python tools/claire_build_verified_memory.py after validation.</div>`;\n\n    panel.innerHTML = `\n      <div class="claire-memory-header">\n        <div>\n          <div class="claire-memory-title">Verified Memory + Recursive Feedback Gate</div>\n          <div class="claire-memory-subtitle">\n            Shows whether a validated Claire output may enter verified memory and whether recursive feedback is allowed.\n          </div>\n        </div>\n        <div style="display:flex; gap:8px; flex-wrap:wrap; justify-content:flex-end;">\n          <span class="claire-memory-pill ${classFor(memoryStatus)}">${escapeHtml(memoryStatus)}</span>\n          <span class="claire-memory-pill ${classFor(feedbackStatus)}">${escapeHtml(feedbackStatus)}</span>\n        </div>\n      </div>\n\n      <div class="claire-memory-grid">\n        ${metric("Run", memory?.run_id || feedback?.run_id || "unknown")}\n        ${metric("Route", memory?.route_selected || feedback?.route_selected || "unknown")}\n        ${metric("Terminal", memory?.terminal_state || feedback?.terminal_state || "missing")}\n        ${metric("Validation", memory?.validation_passed ? "passed" : "not passed")}\n        ${metric("Evidence", memory?.evidence_count ?? 0)}\n        ${metric("Memory", memory?.memory_eligible ? "eligible" : "blocked")}\n        ${metric("Recursion", feedback?.recursive_feedback_allowed ? "allowed" : "blocked")}\n        ${metric("Storage", memory?.storage_mode || "gated report only")}\n      </div>\n\n      <div class="claire-memory-reasons">\n        ${reasonHtml}\n      </div>\n    `;\n  }\n\n  async function boot() {\n    const [memory, feedback] = await Promise.all([\n      fetchFirstJson(MEMORY_PATHS),\n      fetchFirstJson(FEEDBACK_PATHS)\n    ]);\n\n    render(memory || {\n      memory_status: "not_generated",\n      memory_eligible: false,\n      memory_reasons: ["Run tools/claire_build_verified_memory.py after runtime truth and validation authority reports exist."]\n    }, feedback || {\n      feedback_status: "not_generated",\n      recursive_feedback_allowed: false,\n      feedback_reasons: ["Recursive feedback is blocked until verified memory eligibility passes."]\n    });\n  }\n\n  if (document.readyState === "loading") {\n    document.addEventListener("DOMContentLoaded", boot);\n  } else {\n    boot();\n  }\n})();\n', 'docs/dashboard/v17.61_verified_memory_recursive_feedback.md': "# Claire v17.61 — Verified Memory + Recursive Feedback Gate\n\n## Purpose\n\nv17.61 adds the governance gate between validated outputs and future memory/recursive reuse.\n\nThis build does not fake long-term autonomous learning. It creates a deterministic eligibility report that says whether a run may enter verified memory and whether it may be used as recursive feedback.\n\n## Required sequence after a Claire run\n\n```bash\npython tools/claire_build_runtime_truth.py\npython tools/claire_validate_runtime_truth.py\npython tools/claire_build_verified_memory.py\n```\n\n## Outputs\n\n```text\nexports/latest/verified_memory_gate_report.json\nexports/latest/recursive_feedback_gate_report.json\nsrc/frontend/command_center/modern/verified_memory_status.json\nsrc/frontend/command_center/modern/recursive_feedback_status.json\n```\n\n## Core rule\n\n```text\nNo validation pass → no verified memory → no recursive feedback.\n```\n\n## Scope\n\nv17.61 produces:\n\n- memory eligibility status\n- blocker reasons\n- verified memory record payload\n- recursive feedback eligibility status\n- recursive feedback blocker reasons\n- dashboard status bridge\n\nIt does not autonomously mutate Claire's runtime, retrain models, or write permanent memory stores.\n", 'docs/update_packs/v17.61_dashboard_update_pack.md': '# v17.61 Dashboard Update Pack\n\n## Architecture section covered\n\n- Verified Memory\n- Recursive Learning / Feedback\n- Validation-to-Memory gate\n- End-to-End Flow after output validation\n\n## Dashboard files\n\n```text\nsrc/frontend/command_center/modern/claire_verified_memory.js\nsrc/frontend/command_center/modern/verified_memory_contract.json\nsrc/frontend/command_center/modern/recursive_feedback_contract.json\nsrc/frontend/command_center/modern/verified_memory_status.json\nsrc/frontend/command_center/modern/recursive_feedback_status.json\n```\n\nPatched:\n\n```text\nsrc/frontend/command_center/modern/index.html\n```\n\n## Dashboard rule\n\nThe dashboard must show memory and recursion as blocked unless the generated v17.61 reports allow them.\n', 'docs/update_packs/v17.61_system_runtime_update_pack.md': '# v17.61 System Runtime Update Pack\n\n## Runtime purpose\n\nCreate deterministic verified memory and recursive feedback gates.\n\n## Installed files\n\n```text\nsrc/claire/verified_memory/__init__.py\nsrc/claire/verified_memory/io.py\nsrc/claire/verified_memory/memory_record.py\nsrc/claire/verified_memory/memory_gate.py\nsrc/claire/verified_memory/recursive_feedback_gate.py\ntools/claire_build_verified_memory.py\n```\n\n## Post-install test\n\nAfter Claire produces output:\n\n```bash\npython tools/claire_build_runtime_truth.py\npython tools/claire_validate_runtime_truth.py\npython tools/claire_build_verified_memory.py\n```\n\nExpected outputs:\n\n```text\nexports/latest/verified_memory_gate_report.json\nexports/latest/recursive_feedback_gate_report.json\n```\n\n## Safety\n\nThe pack does not fake autonomous memory writes. It produces a gated report and a memory record payload only.\n', 'data/build_manifests/v17.61_verified_memory_manifest.json': '{\n  "version": "17.61",\n  "name": "Verified Memory + Recursive Feedback Gate",\n  "build_type": "system_runtime_and_dashboard_bridge",\n  "purpose": "Govern whether validated Claire outputs may enter verified memory and recursive feedback.",\n  "depends_on": [\n    "v17.59 Runtime Truth Backbone + Dashboard Data Contract",\n    "v17.60 Validation Authority + Evidence Traceability"\n  ],\n  "installed_files": [\n    "docs/dashboard/v17.61_verified_memory_recursive_feedback.md",\n    "docs/update_packs/v17.61_dashboard_update_pack.md",\n    "docs/update_packs/v17.61_system_runtime_update_pack.md",\n    "src/claire/verified_memory/__init__.py",\n    "src/claire/verified_memory/io.py",\n    "src/claire/verified_memory/memory_gate.py",\n    "src/claire/verified_memory/memory_record.py",\n    "src/claire/verified_memory/recursive_feedback_gate.py",\n    "src/frontend/command_center/modern/claire_verified_memory.js",\n    "src/frontend/command_center/modern/recursive_feedback_contract.json",\n    "src/frontend/command_center/modern/recursive_feedback_status.json",\n    "src/frontend/command_center/modern/verified_memory_contract.json",\n    "src/frontend/command_center/modern/verified_memory_status.json",\n    "tools/claire_build_verified_memory.py"\n  ],\n  "runtime_outputs": [\n    "exports/latest/verified_memory_gate_report.json",\n    "exports/latest/recursive_feedback_gate_report.json"\n  ],\n  "post_install_commands": [\n    "python tools/claire_build_runtime_truth.py",\n    "python tools/claire_validate_runtime_truth.py",\n    "python tools/claire_build_verified_memory.py"\n  ],\n  "safety": {\n    "rollback_backups": true,\n    "launcher_path_preserved": "src/frontend/command_center/modern/index.html",\n    "no_fake_memory_storage": true,\n    "no_autonomous_runtime_mutation": true,\n    "memory_requires_validation_pass": true\n  }\n}\n'}

INDEX_SCRIPT = "claire_verified_memory.js"

def utc_stamp() -> str:
    return datetime.utcnow().strftime("%Y%m%d_%H%M%S")

def project_root() -> Path:
    return Path.cwd().resolve()

def backup_existing(root: Path, relative_path: str, backup_root: Path) -> None:
    target = root / relative_path
    if not target.exists():
        return
    backup_path = backup_root / relative_path
    backup_path.parent.mkdir(parents=True, exist_ok=True)
    if target.is_file():
        shutil.copy2(target, backup_path)
    elif target.is_dir():
        if backup_path.exists():
            shutil.rmtree(backup_path)
        shutil.copytree(target, backup_path)

def write_text(root: Path, relative_path: str, content: str, backup_root: Path) -> None:
    target = root / relative_path
    backup_existing(root, relative_path, backup_root)
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_text(content, encoding="utf-8")

def patch_index_html(root: Path, backup_root: Path) -> bool:
    index_path = root / "src" / "frontend" / "command_center" / "modern" / "index.html"
    if not index_path.exists():
        return False

    html = index_path.read_text(encoding="utf-8", errors="ignore")
    if INDEX_SCRIPT in html:
        return True

    backup_existing(root, "src/frontend/command_center/modern/index.html", backup_root)

    script_tag = '\n<script src="claire_verified_memory.js"></script>\n'
    if "</body>" in html:
        html = html.replace("</body>", script_tag + "</body>", 1)
    else:
        html = html + script_tag

    index_path.write_text(html, encoding="utf-8")
    return True

def write_install_record(root: Path, backup_root: Path, index_patched: bool) -> None:
    record = {
        "version": VERSION,
        "build_name": BUILD_NAME,
        "installed_at_utc": datetime.utcnow().isoformat() + "Z",
        "project_root": str(root),
        "backup_root": str(backup_root),
        "index_patched": index_patched,
        "files_written": sorted(FILES.keys()),
        "post_install_commands": [
            "python tools/claire_build_runtime_truth.py",
            "python tools/claire_validate_runtime_truth.py",
            "python tools/claire_build_verified_memory.py"
        ]
    }
    record_path = root / "data" / "build_manifests" / "v17.61_install_record.json"
    record_path.parent.mkdir(parents=True, exist_ok=True)
    record_path.write_text(json.dumps(record, indent=2) + "\n", encoding="utf-8")

def main() -> None:
    root = project_root()
    backup_root = root / "backups" / f"claire_v17_61_{utc_stamp()}"
    backup_root.mkdir(parents=True, exist_ok=True)

    for relative_path, content in FILES.items():
        write_text(root, relative_path, content, backup_root)

    index_patched = patch_index_html(root, backup_root)
    write_install_record(root, backup_root, index_patched)

    print("=" * 72)
    print(f"Claire v{VERSION} installed: {BUILD_NAME}")
    print("=" * 72)
    print(f"Project root: {root}")
    print(f"Backups:      {backup_root}")
    print("")
    print("Installed verified memory gate, recursive feedback gate,")
    print("dashboard contracts, dashboard bridge, docs, and manifests.")
    print("")
    print("After Claire produces run output, run:")
    print("  python tools/claire_build_runtime_truth.py")
    print("  python tools/claire_validate_runtime_truth.py")
    print("  python tools/claire_build_verified_memory.py")
    print("")
    print("Expected generated outputs:")
    print("  exports/latest/verified_memory_gate_report.json")
    print("  exports/latest/recursive_feedback_gate_report.json")
    print("")
    if index_patched:
        print("Dashboard bridge loaded from:")
        print("  src/frontend/command_center/modern/claire_verified_memory.js")
    else:
        print("Note: index.html was not found. The dashboard bridge file was installed,")
        print("but automatic script injection could not be completed.")
    print("=" * 72)

if __name__ == "__main__":
    main()
